LinK36:
本题的基本方法是采用二分法
⚠️注意：最小预算值一定>=所有预算中最大的预算！
check函数：cnt用于计算组数，sum用于计算每一组的数字之和
将所有预算看成一个数组，每次将数组中的数一个个输入进去求sum。若sum<=limit，则继续往sun中➕预算；反之则组数+1，重新从这个数往下计算sum。
二分法中下限为单日最高预算，上限为所有预算之和，mid = l + (r-l)/2（防止溢出，等价于 (l+r)/2），持续缩小范围，结合check函数的判断最终得出答案
源码：
#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;
 const int MAXN=100005;
 int a[MAXN];
 int n,m;
 bool check(int limit){
    int cnt=1;
    int sum=0;
    for(int i=0;i<n;++i){
        if(sum+a[i]>limit){
            cnt++;
            sum=a[i];
        }else{
            sum+=a[i];
        }
    }
    return cnt<=m;
 }
 int main(){
     ios::sync_with_stdio(false);
     cin.tie(0);
     cin>>n>>m;
     int l=0,r=0;
     for(int i=0;i<n;++i){
        cin>>a[i];
        l=max(l,a[i]);
        r+=a[i];
     }
     int ans=r;
     while(l<=r){
        int mid=l+(r-l)/2;
        if(check(mid)){
            ans=mid;
            r=mid-1;
        }else{
            l=mid+1;
        }
     }
     cout<<ans<<endl;
     return 0;
 }

LinK37:
这道题翻译成人话就是每个人只拿一种类型的蛋糕，且蛋糕的量必须一样。
这种前提下就是极端条件下有的蛋糕太小了甚至直接作废（如 3 4 5分给两个人，则每个人最多拿4，3则作废）
思路依然是用二分法。初始l=0，r=最大蛋糕的体积。定义vol用来存放不同蛋糕的体积，cnt为份数，check函数传入一个假设的单人蛋糕体积 x，判断：所有蛋糕全部切割后，能分出的完整份数（强制取整），够不够分给总人数（F+1）。高了mid当r；反之当l。
源码：
#include <iostream>
#include <iomanip>
#include <cmath>
#include <algorithm>
using namespace std;

const double PI=acos(-1.0);
const double eps=1e-6;
const int MAXN=100005;
double vol[MAXN];
int N,F;

bool check(double x){
    int cnt =0;          
    int total=F+1; 
    for(int i=0;i<N;++i){
        cnt+=(int)(vol[i]/x);
        if(cnt>=total) return true;
    }
    return cnt>=total;
}
int main(){
    ios::sync_with_stdio(false);
    cin.tie(0);
    cin>>N>>F;
    double l=0,r=0;
    for(int i=0;i<N;++i){
        int r0;
        cin>>r0;
        vol[i]=PI*r0*r0;
        r=max(r,vol[i]);
    }
    while(r-l>eps){
        double mid=(l+r)/2;
        if(check(mid))
            l=mid;
        else
            r=mid;
    }
    cout<<fixed<<setprecision(3)<<l<<endl;
    return 0;
}
